package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreEmptyLines() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        Method method = CSVFormat.class.getDeclaredMethod("withIgnoreEmptyLines");
        method.setAccessible(true);
        CSVFormat result = (CSVFormat) method.invoke(csvFormat);

        // Then
        assertTrue(result.getIgnoreEmptyLines());
    }
}
